update fin_detail_ledger
groupid = #{groupid}, subject_id = #{subjectId}, voucher_id = #{voucherId}, entry_id = #{entryId}, voucher_date = #{voucherDate}, voucher_no = #{voucherNo}, summary = #{summary}, debit_amount = #{debitAmount}, credit_amount = #{creditAmount}, balance = #{balance}, balance_direction = #{balanceDirection}, created_time = #{createdTime},
where detail_id = #{detailId}

