SELECT fdl.detail_id, fdl.groupid, fdl.subject_id, s.subject_code, fdl.voucher_id, fdl.entry_id,
       fdl.voucher_date, fdl.voucher_no, fdl.summary, fdl.debit_amount, fdl.credit_amount,
       fdl.balance, fdl.balance_direction, fdl.created_time
FROM fin_detail_ledger fdl
         JOIN fin_accounting_subjects s ON fdl.subject_id = s.subject_id AND fdl.groupid = s.groupid
WHERE fdl.groupid = #{groupid}
  AND s.subject_code = #{subjectCode}
  AND fdl.voucher_date BETWEEN #{startDate} AND #{endDate}
ORDER BY fdl.voucher_date, fdl.detail_id

