SELECT fdl.detail_id, fdl.groupid, fdl.subject_id, s.subject_code, fdl.voucher_id, fdl.entry_id,
       fdl.voucher_date, fdl.voucher_no, fdl.summary, fdl.debit_amount, fdl.credit_amount,
       fdl.balance, fdl.balance_direction, fdl.created_time
FROM fin_detail_ledger fdl
         JOIN fin_accounting_subjects s ON fdl.subject_id = s.subject_id AND fdl.groupid = s.groupid
WHERE fdl.groupid = #{groupid}
  AND s.subject_code = #{subjectCode}
  AND fdl.voucher_date <= #{endDate}
ORDER BY fdl.voucher_date DESC, fdl.detail_id DESC
    LIMIT 1

WITH begin_bal AS ( SELECT subject_id, SUM(debit_amount) - SUM(credit_amount) AS begin_balance_signed FROM fin_detail_ledger WHERE groupid = #{params.groupid} AND voucher_date < #{params.startDate} GROUP BY subject_id ), dl_summary AS ( SELECT subject_id, SUM(debit_amount) AS debit_total, SUM(credit_amount) AS credit_total FROM fin_detail_ledger WHERE groupid = #{params.groupid} AND voucher_date >= #{params.startDate} AND voucher_date <= #{params.endDate} GROUP BY subject_id ), year_summary AS ( SELECT subject_id, SUM(debit_amount) AS year_debit_total, SUM(credit_amount) AS year_credit_total FROM fin_detail_ledger WHERE groupid = #{params.groupid} AND voucher_date >= DATE_FORMAT(#{params.startDate}, '%Y-01-01') AND voucher_date <= #{params.endDate} GROUP BY subject_id ) SELECT s.subject_code AS subjectCode, s.subject_name AS subjectName, s.subject_type AS subjectType, st.name AS subjectTypeName, s.direction AS direction, ABS(COALESCE(b.begin_balance_signed, 0)) AS beginBalance, CASE WHEN COALESCE(b.begin_balance_signed, 0) >= 0 THEN 1 ELSE 2 END AS beginDirection, COALESCE(d.debit_total, 0) AS debitTotal, COALESCE(d.credit_total, 0) AS creditTotal, COALESCE(y.year_debit_total, 0) AS yearDebitTotal, COALESCE(y.year_credit_total, 0) AS yearCreditTotal, -- 期末余额 = 期初余额(带符号) + 本期借方 - 本期贷方 COALESCE(b.begin_balance_signed, 0) + COALESCE(d.debit_total, 0) - COALESCE(d.credit_total, 0) AS endBalanceSigned FROM fin_accounting_subjects s LEFT JOIN fin_subject_type st ON s.subject_type = st.id LEFT JOIN begin_bal b ON s.subject_id = b.subject_id LEFT JOIN dl_summary d ON s.subject_id = d.subject_id LEFT JOIN year_summary y ON s.subject_id = y.subject_id WHERE s.groupid = #{params.groupid}
AND s.subject_code IN
#{code}
AND s.status = 1 ORDER BY s.subject_code

SELECT


        COALESCE(SUM(
        CASE
        WHEN dl_end.balance_direction = 1 THEN dl_end.balance
        WHEN dl_end.balance_direction = 2 THEN -dl_end.balance
        WHEN s.direction = 1 THEN 0
        WHEN s.direction = 2 THEN 0
        ELSE 0
        END
        ), 0)
        FROM fin_accounting_subjects s
        LEFT JOIN (
        SELECT s2.subject_code, dl2.balance, dl2.balance_direction
        FROM fin_detail_ledger dl2
        JOIN fin_accounting_subjects s2 ON dl2.subject_id = s2.subject_id AND dl2.groupid = s2.groupid
        WHERE dl2.groupid = #{groupid}
        AND dl2.voucher_date <= #{endDate}
        AND (dl2.detail_id) IN (
        SELECT MAX(fdl.detail_id)
        FROM fin_detail_ledger fdl
        JOIN fin_accounting_subjects s3 ON fdl.subject_id = s3.subject_id AND fdl.groupid = s3.groupid
        WHERE fdl.groupid = #{groupid}
        AND fdl.voucher_date <= #{endDate}
        AND s3.subject_code LIKE #{subjectCodePattern}
        GROUP BY s3.subject_code
        )
        ) dl_end ON s.subject_code = dl_end.subject_code
        WHERE s.groupid = #{groupid}

            AND s.subject_code LIKE #{subjectCodePattern}


        AND s.status = 1


        COALESCE(SUM(
        CASE
        WHEN dl_begin.balance_direction = 1 THEN dl_begin.balance
        WHEN dl_begin.balance_direction = 2 THEN -dl_begin.balance
        WHEN s.direction = 1 THEN 0
        WHEN s.direction = 2 THEN 0
        ELSE 0
        END
        ), 0)
        FROM fin_accounting_subjects s
        LEFT JOIN (
        SELECT s2.subject_code, dl1.balance, dl1.balance_direction
        FROM fin_detail_ledger dl1
        JOIN fin_accounting_subjects s2 ON dl1.subject_id = s2.subject_id AND dl1.groupid = s2.groupid
        WHERE dl1.groupid = #{groupid}
        AND dl1.voucher_date <= #{startDate}
        AND (dl1.detail_id) IN (
        SELECT MAX(fdl.detail_id)
        FROM fin_detail_ledger fdl
        JOIN fin_accounting_subjects s3 ON fdl.subject_id = s3.subject_id AND fdl.groupid = s3.groupid
        WHERE fdl.groupid = #{groupid}
        AND fdl.voucher_date < #{startDate}
        AND s3.subject_code LIKE #{subjectCodePattern}
        GROUP BY s3.subject_code
        )
        ) dl_begin ON s.subject_code = dl_begin.subject_code
        WHERE s.groupid = #{groupid}

            AND s.subject_code LIKE #{subjectCodePattern}

        AND s.status = 1


        COALESCE(SUM(dl.debit_amount), 0)
        FROM fin_detail_ledger dl
        JOIN fin_accounting_subjects s ON dl.subject_id = s.subject_id AND dl.groupid = s.groupid
        WHERE dl.groupid = #{groupid}

            AND s.subject_code LIKE #{subjectCodePattern}

        AND dl.voucher_date BETWEEN #{startDate} AND #{endDate}


        COALESCE(SUM(dl.credit_amount), 0)
        FROM fin_detail_ledger dl
        JOIN fin_accounting_subjects s ON dl.subject_id = s.subject_id AND dl.groupid = s.groupid
        WHERE dl.groupid = #{groupid}

            AND s.subject_code LIKE #{subjectCodePattern}

        AND dl.voucher_date BETWEEN #{startDate} AND #{endDate}

    0
